<?phprequire_once 'config/database.php';$message = '';if ($_SERVER['REQUEST_METHOD'] === 'POST') {    $first_name = trim($_POST['first_name']);    $last_name = trim($_POST['last_name']);    $email = trim($_POST['email']);    $password = $_POST['password'];    if (!empty($email) && !empty($password)) {        $password_hash = password_hash(            $password,            PASSWORD_DEFAULT        );        $stmt = $pdo->prepare("            INSERT INTO users            (                first_name,                last_name,                email,                password_hash            )            VALUES            (                :first_name,                :last_name,                :email,                :password_hash            )        ");        try {            $stmt->execute([                'first_name' => $first_name,                'last_name' => $last_name,                'email' => $email,                'password_hash' => $password_hash            ]);header('Location: login.php?registered=1');exit;            $message = "Account created successfully.";        } catch (PDOException $e) {            $message = "Error creating account.";        }    }}?><?php include 'includes/header.php'; ?><title>TrainTote Ops Manager - Register</title></head><body><div class="container mt-5"><div class="row justify-content-center"><div class="col-md-6 col-lg-5"><h1 class="mb-4 text-center">🚂 TrainTote Ops Manager</h1><div class="card"><div class="card-body"><h3 class="mb-4">Create Account</h3><?php if($message): ?><div class="alert alert-info"><?php echo htmlspecialchars($message); ?></div><?php endif; ?><form method="post"><div class="mb-3"><label>First Name</label><inputtype="text"name="first_name"class="form-control"></div><div class="mb-3"><label>Last Name</label><inputtype="text"name="last_name"class="form-control"></div><div class="mb-3"><label>Email</label><inputtype="email"name="email"class="form-control"required></div><div class="mb-3"><label>Password</label><inputtype="password"name="password"class="form-control"required></div><buttontype="submit"class="btn btn-primary w-100">Create Account</button></form></div></div></div></div></div><?php include 'includes/footer.php'; ?>